(function () {
    function syncScroll() {
        // Target the specific scrollable div generated by Dash DataTable
        // When style_table={'overflowX': 'auto'} is set, the scrolling happens on:
        // .dash-spreadsheet-container

        // We will add a specific class 'sync-table' to our DataTables
        const tables = document.querySelectorAll('.sync-table .dash-spreadsheet-container');

        if (tables.length === 0) return;

        tables.forEach(table => {
            if (table.getAttribute('data-sync-attached') === 'true') return;

            table.addEventListener('scroll', function (e) {
                const scrollLeft = e.target.scrollLeft;
                tables.forEach(otherTable => {
                    if (otherTable !== e.target) {
                        // Check if update is needed to avoid infinite loop
                        if (Math.abs(otherTable.scrollLeft - scrollLeft) > 1) {
                            otherTable.scrollLeft = scrollLeft;
                        }
                    }
                });
            });

            table.setAttribute('data-sync-attached', 'true');
        });
    }

    // Check periodically for new tables (since Dash renders dynamically)
    setInterval(syncScroll, 1000);
})();
